// DecodeRemoveUserRequest returns a decoder for requests sent to the
// organizations removeUser endpoint.
func DecodeRemoveUserRequest(mux goahttp.Muxer, decoder func(*http.Request) goahttp.Decoder) func(*http.Request) (*organizations.RemoveUserPayload, error) {
	return func(r *http.Request) (*organizations.RemoveUserPayload, error) {
		var payload *organizations.RemoveUserPayload
		var (
			userID       string
			sessionToken *string
			err          error
		)
		userID = r.URL.Query().Get("user_id")
		if userID == "" {
			err = goa.MergeErrors(err, goa.MissingFieldError("user_id", "query string"))
		}
		sessionTokenRaw := r.Header.Get("Gram-Session")
		if sessionTokenRaw != "" {
			sessionToken = &sessionTokenRaw
		}
		if err != nil {
			return payload, err
		}
		payload = NewRemoveUserPayload(userID, sessionToken)
		if payload.SessionToken != nil {
			if strings.Contains(*payload.SessionToken, " ") {
				// Remove authorization scheme prefix (e.g. "Bearer")
				cred := strings.SplitN(*payload.SessionToken, " ", 2)[1]
				payload.SessionToken = &cred
			}
		}

		return payload, nil
	}
}

